import { NavLink } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LayoutDashboard, Users, FileText, Settings, LogOut, PlaneLanding, PlaneTakeoff, X } from 'lucide-react';
import logo from '../assets/logo.png';

const Sidebar = ({ onClose }) => {
    const { logout, user } = useAuth();

    const handleLogout = () => {
        logout();
        if (onClose) onClose();
    };

    const NavItem = ({ to, icon: Icon, label, end = false }) => (
        <NavLink
            to={to}
            end={end}
            onClick={() => onClose && onClose()}
            className={({ isActive }) => `flex items-center space-x-3 px-4 py-3 rounded-xl transition ${isActive ? 'bg-[#f28c00]/10 text-[#f28c00]' : 'text-slate-300 hover:bg-slate-800 hover:text-white'}`}
        >
            <Icon className="w-5 h-5" />
            <span className="font-medium">{label}</span>
        </NavLink>
    );

    return (
        <div className="w-64 bg-slate-900 text-white flex flex-col h-full shadow-2xl overflow-y-auto">
            <div className="p-6 border-b border-slate-800 flex flex-col items-center text-center relative">
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 text-slate-400 hover:text-white lg:hidden"
                >
                    <X className="w-6 h-6" />
                </button>
                <img src={logo} alt="Hiru Ayurveda Resorts Logo" className="w-[85%] h-auto mb-3 drop-shadow-lg rounded-lg" />
                <h2 className="text-sm font-semibold text-slate-300 tracking-wide mt-2">
                    Hiru Ayurveda Resorts
                </h2>
                <p className="text-xs text-slate-400 mt-1 uppercase tracking-tighter">Guest Management System</p>
            </div>

            <nav className="flex-1 px-4 py-6 space-y-2">
                <NavItem to="/" icon={LayoutDashboard} label="Dashboard" end />
                <NavItem to="/guests" icon={Users} label="Guests" />
                <NavItem to="/arrivals" icon={PlaneLanding} label="Arrival List" />
                <NavItem to="/departures" icon={PlaneTakeoff} label="Departure List" />
                <NavItem to="/reports" icon={FileText} label="Reports" />

                {(user?.role === 'Admin') && (
                    <NavItem to="/settings" icon={Settings} label="Settings" />
                )}
            </nav>

            <div className="p-4 border-t border-slate-800">
                <button onClick={handleLogout} className="flex items-center space-x-3 text-slate-400 hover:text-white w-full px-4 py-2 transition rounded-xl hover:bg-slate-800/50">
                    <LogOut className="w-5 h-5" />
                    <span>Logout</span>
                </button>
            </div>
        </div>
    );
};

export default Sidebar;

import { createContext, useContext, useState, useEffect } from 'react';
import PropTypes from 'prop-types';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [token, setToken] = useState(localStorage.getItem('token') || null);

    useEffect(() => {
        // Ideally verify token here or load user data from decoded token/localStorage
        const savedUser = localStorage.getItem('user');
        if (savedUser && token) {
            setUser(JSON.parse(savedUser));
        }
    }, [token]);

    const login = (userData, jwtToken) => {
        setUser(userData);
        setToken(jwtToken);
        localStorage.setItem('user', JSON.stringify(userData));
        localStorage.setItem('token', jwtToken);
    };

    const logout = () => {
        setUser(null);
        setToken(null);
        localStorage.removeItem('user');
        localStorage.removeItem('token');
    };

    return (
        <AuthContext.Provider value={{ user, token, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

AuthProvider.propTypes = {
    children: PropTypes.node.isRequired
};

export const useAuth = () => useContext(AuthContext);
